const chunks = [
  {
    title: "Ministry of Education Haze & School Closure Protocol (Circular No. 1/2019)",
    category: "school_closure",
    source: "MOE Circular 1/2019",
    content: "Under the Ministry of Education (MOE) Circular No. 1/2019 (Surat Pekeliling Ikhtisas KPM), school administrations in Malaysia are mandated to execute immediate physical closures as soon as the Air Pollutant Index (API/IPU) at their nearest Department of Environment (DOE) monitoring station exceeds 200 (Very Unhealthy).\n\nWhen the local API crosses 200, schools must immediately shift to Home-Based Teaching and Learning (PdPR / Pengajaran dan Pembelajaran di Rumah). School heads do not need to wait for District Education Office (PPD) or State Education Department (JPN) approval to enact closures, but they must notify them immediately. The closure does not suspend public examinations (such as SPM or STPM), which will proceed under specialized safety protocols.\n\nIf the API hovers between 101 and 150 (Unhealthy), school administrators must suspend all outdoor physical education classes, assemblies, and extracurricular activities. Parents can opt to keep their children home if concerned, but they must formally write to the school."
  },
  {
    title: "Environmental Quality Act 1974 Section 29A — Open Burning Prohibition",
    category: "open_burning_law",
    source: "EQA 1974 s.29A",
    content: "Under Section 29A of the Malaysian Environmental Quality Act 1974 (Akta Kualiti Alam Sekeliling 1974), all forms of open burning—including agricultural waste, household trash, construction debris, undergrowth, and peatland clearings—are strictly illegal without written government approval.\n\nFollowing recent legal updates, convicted offenders face a mandatory minimum fine of RM25,000 up to a maximum of RM1,000,000, imprisonment for a term not exceeding 5 years, or both. An additional daily fine of up to RM5,000 can be levied for continuing offenses.\n\nCitizens can report active open burning directly to the Department of Environment (DOE/JAS) National Hotline at 1-800-88-2727, through the online DOE eComplaint app, or by contacting the Fire and Rescue Department (JBPM/Bomba) at 999 for active forest, plantation, or peatland fires. The Open Burning Prevention Action Plan is coordinated regionally by the National Disaster Management Agency (NADMA)."
  },
  {
    title: "Ministry of Health (MOH) Haze Health & Masking Guidelines",
    category: "health_guidance",
    source: "MOH/KKM Haze Advisory",
    content: "The Ministry of Health (MOH/KKM) advises that once the Air Pollutant Index (API) crosses 100 (Unhealthy), vulnerable groups—specifically children, pregnant women, the elderly, and individuals with pre-existing respiratory or cardiovascular diseases (such as asthma, COPD, or bronchitis)—must limit all outdoor physical exposure and wear protective masks when going outside.\n\nStandard surgical masks or fabric cloth masks do not block fine particulate matter (PM2.5). Individuals must wear certified N95, KF94, or KN95 respirators, which are capable of filtering out microscopic haze particles.\n\nOnce the API exceeds 150, the general healthy public is advised to avoid strenuous outdoor cardiovascular activities (like jogging or cycling). If the API breaches 300 (Hazardous), all citizens are strongly advised by NADMA to stay entirely indoors, keep windows closed, and run indoor air purifiers fitted with HEPA filters."
  }
];

return chunks.map(c => ({ json: c }));
